import React from "react";
import PropTypes from "prop-types";
import type { ClearFilterTag } from "../../types/filters/filters";

function Finder__ClearFilterTag(props: ClearFilterTag) {
    const {query, facet, update, dependencies, value} = props;
    const currentQueryFacets = query.facets;
    const keyFacets = Object.keys(currentQueryFacets);
    const valuesFacets = Object.values(currentQueryFacets);
    

    const normalize = (v: string) => v.toLowerCase().trim().replace(/\s+/g, ' ');
    

    const updateQuery = (facetValue: string) => {
        const normValue = normalize(facetValue);
        const newQuery = {
            ...query,
            facets: { ...query.facets }
            };
        
        newQuery.facets = { ...newQuery.facets };
         // clear dependent facets
        if (dependencies){
            dependencies.forEach((dep) => {
            delete newQuery.facets[dep.meta];
        });
        }

        const rawCurrent = newQuery.facets[facet.meta];
        const currentValues: string[] = Array.isArray(rawCurrent)
        ? rawCurrent.map(normalize)
        : rawCurrent
        ? [normalize(rawCurrent)]
        : [];

        // toggle value
        if (currentValues.includes(normValue)) {
        const updated = currentValues.filter(v => v !== normValue);
          if (updated.length > 0) {
              newQuery.facets[facet.meta] = updated;
          } else {
              // remove empty facet entry entirely
              delete newQuery.facets[facet.meta];
          }
        }

        // reset paging / flags
        newQuery.startRank = 1;
        newQuery.misspelling = null;
        newQuery.interacted = true;

        update.query(newQuery);
        update.results(!update.updateState);
    };

    const clearFilterTags = !value && valuesFacets.length > 0 && valuesFacets.flatMap((facetValue, i) => {
      const facetKey = keyFacets[i];
      // facetValue can be a string or array; normalize to array so we render each value separately
      const list = Array.isArray(facetValue) ? facetValue : [facetValue];

      return list.map(v => (
        <button
          key={`${facetKey}-${v}`}
          className="v26-finder__clear-filter-tag"
          onClick={() => updateQuery(v)}
        >
          {v}
        </button>
      ));
    });

    const clearSingleFilterTag = value && (
        <button
          key={`${facet.meta}-${value}`}
          aria-label={`Clear the filter ${value}`}
          className="v26-finder__clear-filter-tag"
          onClick={() => updateQuery(value)}
        >
          {value}
          {props.site === 'city' && (
            <span className='fa-sharp fa-solid fa-xmark icon' />
          )}
        </button>
    );
    
    return (
        <div className="v26-finder__filter v26-finder__tag">
            {clearFilterTags}
            {clearSingleFilterTag}
        </div>
    );
}

export default Finder__ClearFilterTag;

Finder__ClearFilterTag.propTypes = {
  facet: PropTypes.object.isRequired,
  query: PropTypes.object.isRequired,
  update: PropTypes.object.isRequired,
  config: PropTypes.object.isRequired,
  value: PropTypes.string,
};